function sdp_participants_college_details_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('sdp_participants_college_details_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'username' => parseCode('<%%creatorUsername%%>', true),
		'participants_type' => Request::val('participants_type', ''),
		'school_college_name' => Request::val('school_college_name', ''),
		'location' => Request::val('location', ''),
		'latitude' => Request::val('latitude', ''),
		'longitude' => Request::val('longitude', ''),
		'number_of_participants' => Request::val('number_of_participants', ''),
		'start_date' => Request::dateComponents('start_date', '1'),
		'end_date' => Request::dateComponents('end_date', '1'),
		'state' => Request::val('state', ''),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('sdp_participants_college_details_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		sdp_participants_college_details_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

