function sdp_participants_college_details_table_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('sdp_participants_college_details_table', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: sdp_participants_college_details_table_before_delete
	if(function_exists('sdp_participants_college_details_table_before_delete')) {
		$args = [];
		if(!sdp_participants_college_details_table_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `sdp_participants_college_details_table` WHERE `id`='{$selected_id}'", $eo);

	// hook: sdp_participants_college_details_table_after_delete
	if(function_exists('sdp_participants_college_details_table_after_delete')) {
		$args = [];
		sdp_participants_college_details_table_after_delete($selected_id, getMemberInfo(), $args);
	}

