	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='sdp_participants_college_details_table' AND `pkValue`='{$selected_id}'", $eo);
}

function sdp_participants_college_details_table_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('sdp_participants_college_details_table', $selected_id, 'edit')) return false;

	$data = [
		'participants_type' => Request::val('participants_type', ''),
		'school_college_name' => Request::val('school_college_name', ''),
		'location' => Request::val('location', ''),
		'latitude' => Request::val('latitude', ''),
		'longitude' => Request::val('longitude', ''),
		'number_of_participants' => Request::val('number_of_participants', ''),
		'start_date' => Request::dateComponents('start_date', ''),
		'end_date' => Request::dateComponents('end_date', ''),
		'state' => Request::val('state', ''),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('sdp_participants_college_details_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: sdp_participants_college_details_table_before_update
	if(function_exists('sdp_participants_college_details_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!sdp_participants_college_details_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'sdp_participants_college_details_table',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="sdp_participants_college_details_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('sdp_participants_college_details_table', $data['selectedID'], calculated_fields()['sdp_participants_college_details_table']);

	// hook: sdp_participants_college_details_table_after_update
	if(function_exists('sdp_participants_college_details_table_after_update')) {
		if($row = getRecord('sdp_participants_college_details_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!sdp_participants_college_details_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('sdp_participants_college_details_table', $selected_id);
}

